checker_dsl:
EXISTS (`taint flow path P`) {
  (`P has source node S and sink node K where S is an ActiveThreatModelSource, K has associated regular expression literal R, regular expression from R is matched against expression of K, there exists polynomial backtracking term T where T.getRootTerm() equals the regular expression term from K, P flows from S to K, and there does not exist barrier node B on path P where B is a SimpleTypeSanitizer or B's expression is method call M where M calls method methodDef where methodDef's lowercase name matches patterns: "%header%", "%requesturi%", "%requesturl%", "%cookie%" or methodDef's declaring type's lowercase name contains "%cookie%" and methodDef's name starts with "get" or methodDef's declaring type's lowercase name contains "%request%" and methodDef's lowercase name matches patterns: "%get%path%", "get%user%", "%querystring%"`)
}
